def process_aggregation_job(task_data: Dict) -> Dict[str, Any]:
    """Process aggregation job"""
    data_sets = task_data.get('data_sets', [])
    aggregation_type = task_data.get('aggregation_type', 'sum')
    
    results = {}
    
    for dataset_name, values in data_sets:
        if aggregation_type == 'sum':
            results[dataset_name] = sum(values) if values else 0
        elif aggregation_type == 'avg':
            results[dataset_name] = sum(values) / len(values) if values else 0
        elif aggregation_type == 'count':
            results[dataset_name] = len(values)
    
    return {
        'items_processed': len(data_sets),
        'job_type': 'aggregation',
        'aggregation_results': results
    }


